const input = $input.first().json;
const userId = input.user_id || input.payload?.user_id || 'unknown';
const amount = input.amount || input.payload?.amount || 0;
const action = input.action || input.payload?.action || 'ai_generation';
const description = input.description || input.payload?.description || action;

return {
  user_id: userId,
  amount: parseInt(amount) || 0,
  action: action,
  description: description,
  balance_check_url: `http://aitoearn-nginx:80/api/user/subscription`,
  warning: amount <= 0 ? '无效的扣费金额' : null,
  timestamp: new Date().toISOString()
};

const data = $input.first().json;

// 金额有效性检查
if (data.amount <= 0) {
  return {
    status: 'rejected',
    reason: '无效的扣费金额',
    user_id: data.user_id,
    timestamp: data.timestamp
  };
}

// 大额扣费风险标记
const isLargeAmount = data.amount > 100;

return {
  status: 'pending',
  user_id: data.user_id,
  amount: data.amount,
  action: data.action,
  description: data.description,
  risk_level: isLargeAmount ? 'HIGH' : 'LOW',
  risk_flags: isLargeAmount ? ['large_amount', 'needs_audit'] : [],
  timestamp: data.timestamp
};

const data = $input.first().json;

return {
  success: data.status !== 'rejected',
  transaction_id: 'txn_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6),
  user_id: data.user_id,
  amount: data.amount,
  action: data.action,
  risk_level: data.risk_level,
  risk_flags: data.risk_flags || [],
  // 注: 实际扣费需调用后端 credits/deduct API
  // 当前 CreditsModule 待 Docker 重建后部署
  message: data.status === 'rejected' ? data.reason : `积分扣费请求已受理: ${data.amount} 积分`,
  timestamp: data.timestamp || new Date().toISOString()
};
